    const ALL_STATUSES = [
        "COSMETIC",
        "VARIANT",
        "BILINGUAL",
        "NEAR",
        "WRONG_TYPE",
        "WRONG_STREET",
        "WRONG_CITY",
        "NOT_FOUND",
        "UNNAMED",
        "UNDER_LOCK",
        "MICRO_SEGMENT",
        "LOOP",
        "NARROW_MISUSE",
        "OVER_LOCK",
        "UNNAMED_NO_MATCH",
    ];
    const LOCK_STATUSES = ["UNDER_LOCK", "OVER_LOCK"];
    const LOCK_DEFAULT_MIN_RANK = 2;
    function defaultEnabledStatuses(userRank) {
        const lockOk = userRank !== null && userRank >= LOCK_DEFAULT_MIN_RANK;
        return ALL_STATUSES.filter((s) => s !== "UNNAMED_NO_MATCH" && (lockOk || !LOCK_STATUSES.includes(s)));
    }
    const DEFAULT_SETTINGS = {
        version: 2,
        enabled: true,
        autoScan: true,
        minZoom: 15,
        checkedRoadTypes: ROAD_TYPE_OPTIONS.filter((r) => r.defaultChecked).map((r) => r.id),
        enabledStatuses: ALL_STATUSES.filter((s) => s !== "UNNAMED_NO_MATCH"),
        altNameCountsAsOk: true,
        cityScoping: "off",
        showMapLabels: true,
        keepOldNameAsAlt: false,
        ignoredKeys: [],
        language: "auto",
        guidelineChecks: true,
        editPanelHelper: true,
        geometryMatching: true,
        viewportOnly: true,
        editableOnly: false,
    };
    const STORAGE_KEY = "wme-ch-name-check.settings";
    function migrateSettings(parsed) {
        if (parsed.version === 1) {
            const legacy = parsed;
            const enabledStatuses = legacy.showCosmetic === false
                ? ALL_STATUSES.filter((status) => status !== "COSMETIC")
                : [...ALL_STATUSES];
            return { ...DEFAULT_SETTINGS, ...parsed, version: 2, enabledStatuses };
        }
        return { ...DEFAULT_SETTINGS, ...parsed, version: 2 };
    }
    function loadSettings(userRank = null) {
        try {
            const raw = localStorage.getItem(STORAGE_KEY);
            if (!raw)
                return { ...DEFAULT_SETTINGS, enabledStatuses: defaultEnabledStatuses(userRank) };
            return migrateSettings(JSON.parse(raw));
        }
        catch (err) {
            log.warn("Failed to load settings, using defaults", err);
            return { ...DEFAULT_SETTINGS, enabledStatuses: defaultEnabledStatuses(userRank) };
        }
    }
    function saveSettings(settings) {
        try {
            localStorage.setItem(STORAGE_KEY, JSON.stringify(settings));
        }
        catch (err) {
            log.warn("Failed to save settings", err);
        }
    }
    class SettingsStore {
        constructor(userRank = null) {
            this.settings = loadSettings(userRank);
        }
        get() {
            return this.settings;
        }
        update(partial) {
            this.settings = { ...this.settings, ...partial };
            saveSettings(this.settings);
            return this.settings;
        }
    }

    function wgs84ToLv95(lon, lat) {
        const phi = (lat * 3600 - 169_028.66) / 10_000;
        const lambda = (lon * 3600 - 26_782.5) / 10_000;
        const e = 2_600_072.37 +
            211_455.93 * lambda -
            10_938.51 * lambda * phi -
            0.36 * lambda * phi * phi -
            44.54 * lambda * lambda * lambda;
        const n = 1_200_147.07 +
            308_807.95 * phi +
            3_745.25 * lambda * lambda +
            76.63 * phi * phi -
            194.56 * lambda * lambda * phi +
            119.79 * phi * phi * phi;
        return { e, n };
    }
    const REGISTER_LAYER = "ch.swisstopo.amtliches-strassenverzeichnis";
    function mapGeoAdminUrl(lon, lat, locale) {
        const { e, n } = wgs84ToLv95(lon, lat);
        const params = new URLSearchParams({
            lang: locale,
            E: e.toFixed(1),
            N: n.toFixed(1),
            zoom: "11",
            layers: REGISTER_LAYER,
        });
        return `https://map.geo.admin.ch/?${params.toString()}`;
    }
    function mapGeoAdminUrlForGeometry(geometry, locale) {
        const points = samplePoints(geometry);
        const mid = points[Math.floor(points.length / 2)] ?? [0, 0];
        return mapGeoAdminUrl(mid[0], mid[1], locale);
    }

